    { id: 9, name: 'CSS Grid Layout Mastery', category: 'frontend' },
    { id: 10, name: 'Machine Learning with Python', category: 'data' },
];

// Custom debounce hook — returns a value that updates only after `delay`ms
// of no changes. Also reports whether a debounce is currently pending so we
// can show a "Searching..." indicator.
function useDebouncedValue(value, delay) {
    const [debouncedValue, setDebouncedValue] = useState(value);
    const [isPending, setIsPending] = useState(false);
    const timeoutRef = useRef(null);

    useEffect(() => {
        // Value changed: a debounce is now pending.
        setIsPending(true);
        timeoutRef.current = setTimeout(() => {
            setDebouncedValue(value);
            setIsPending(false);
        }, delay);

        // Requirement #8: clean up the pending timeout on change/unmount
        // to prevent memory leaks and stale updates.
        return () => clearTimeout(timeoutRef.current);
    }, [value, delay]);

    return [debouncedValue, isPending];
