// Escape regex metacharacters so special chars in the query (e.g. "(", "*",
// "[") are treated literally and never throw. (Requirement #9)
function escapeRegExp(str) {
    return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// Highlight every case-insensitive match of `query` within `text` by wrapping
// matched portions in <mark>. (Requirement #6)
function highlightMatch(text, query) {
    if (!query) return text;

    const regex = new RegExp(`(${escapeRegExp(query)})`, 'gi');
    const parts = text.split(regex);

    return parts.map((part, i) =>
        // Odd-indexed parts are the captured matches.
        regex.test(part) && part.toLowerCase() === query.toLowerCase() ? (
            <mark key={i}>{part}</mark>
        ) : (
            part
        )
    );
}

function ResourceList() {
    const [query, setQuery] = useState('');
    const [debouncedQuery, isPending] = useDebouncedValue(query, 300);

    // Treat whitespace-only input as empty. (Requirement #9 / #5)
    const trimmedQuery = debouncedQuery.trim();

    const filteredItems = useMemo(() => {
        if (!trimmedQuery) return ITEMS; // empty -> show all (Requirement #5)
        const needle = trimmedQuery.toLowerCase();
        return ITEMS.filter(item => item.name.toLowerCase().includes(needle));
    }, [trimmedQuery]);

    // Only show the indicator when there's something to actually search for.
    const showSearching = isPending && query.trim() !== '';

    return (
        <div>
            <h2>Resources</h2>

            <input
                type="text"
                value={query}
                onChange={e => setQuery(e.target.value)}
                placeholder="Search resources..."
                aria-label="Search resources"
            />

            {showSearching && <p aria-live="polite">Searching...</p>}

            {!showSearching && filteredItems.length === 0 ? (
                <p>No results found</p>
            ) : (
                <ul>
                    {filteredItems.map(item => (
                        <li key={item.id}>
                            <strong>{highlightMatch(item.name, trimmedQuery)}</strong>{' '}
                            <span>({item.category})</span>
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
}

export default ResourceList;
